import React from 'react';
import { Link } from 'react-router-dom';
import CTA from '../components/CTA';
import './Studio.css';

const team = [
  {
    name: 'Alex Morgan',
    role: 'Founder & Creative Director',
    img: 'https://framerusercontent.com/images/ZbBWT6HbhupH7FIQ25kMqURKqgQ.png',
  },
  {
    name: 'Sarah Chen',
    role: 'Lead UI/UX Designer',
    img: 'https://framerusercontent.com/images/4R7HUMP3WUGx8mrykN4wq0PhGo.jpg',
  },
  {
    name: 'Marcus Reid',
    role: 'Head of Development',
    img: 'https://framerusercontent.com/images/PdVnZymDIiku8ywz3BUxAbly3U.png',
  },
  {
    name: 'Nina Patel',
    role: 'Motion Design Lead',
    img: 'https://framerusercontent.com/images/i2sOp7CKOOg8s3DCiTAncc9YGY.png',
  },
];

const values = [
  { title: 'Bold Creativity', desc: 'We push boundaries and challenge conventions to deliver designs that truly stand out in a crowded digital landscape.' },
  { title: 'Precision Craft', desc: 'Every pixel matters. We obsess over details to ensure every deliverable meets the highest standards of quality.' },
  { title: 'Client Partnership', desc: 'We treat every project as a collaboration, working closely with clients to bring their unique vision to life.' },
  { title: 'Future Thinking', desc: 'We design with longevity in mind, creating solutions that adapt and grow with your brand over time.' },
];

export default function Studio() {
  return (
    <main className="studio-page">
      {/* Page Hero */}
      <section className="page-hero studio-hero">
        <div className="container page-hero-content">
          <p className="section-label">About the Studio</p>
          <h1 className="page-hero-title">
            We're Scarlet.<br />We design bold.
          </h1>
          <p className="page-hero-sub">
            Founded in 2010, Scarlet Design Studio has been at the forefront of digital design,
            helping brands craft identities and experiences that captivate and convert.
          </p>
        </div>
        <div className="studio-hero-img">
          <img src="https://framerusercontent.com/images/LG47yzJKYPaE9iSMjClLZQLV0Iw.jpg" alt="Studio" />
        </div>
      </section>

      {/* Stats */}
      <section className="studio-stats-section">
        <div className="container">
          <div className="studio-stats-grid">
            {[
              { v: '15+', l: 'Years of Experience' },
              { v: '100+', l: 'Projects Completed' },
              { v: '97%', l: 'Client Satisfaction' },
              { v: '200+', l: 'Happy Clients' },
            ].map(s => (
              <div key={s.l} className="studio-stat">
                <span className="s-val">{s.v}</span>
                <span className="s-lbl">{s.l}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Values */}
      <section className="studio-values">
        <div className="container">
          <p className="section-label">Our Values</p>
          <h2 className="section-heading">What drives us.</h2>
          <div className="values-grid">
            {values.map(v => (
              <div key={v.title} className="value-card">
                <h3 className="value-title">{v.title}</h3>
                <p className="value-desc">{v.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Team */}
      <section className="studio-team">
        <div className="container">
          <p className="section-label">The Team</p>
          <h2 className="section-heading">The people behind the work.</h2>
          <div className="team-grid">
            {team.map(m => (
              <div key={m.name} className="team-card">
                <div className="team-img">
                  <img src={m.img} alt={m.name} />
                </div>
                <h3 className="team-name">{m.name}</h3>
                <p className="team-role">{m.role}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <CTA />
    </main>
  );
}
